import React, { useState, useEffect } from 'react';
import { authAPI, pgAPI } from '../services/api';
import { splitQuestions } from '../utils/splitQuestions';
import { Button, Select, Textarea, Alert, PageHeader, Card, Badge, EmptyState } from '../components/ui';
import ResultsPanel from '../components/ui/ResultsPanel';
import { Database, Send, Sparkles } from 'lucide-react';
import './QueryPage.css';

const SAMPLE_QUESTIONS = [
  'Show total revenue by region',
  'Which customers placed the most orders last month?',
  'Show top 10 products by sales volume',
  'What is the average order value by customer segment?',
  'Total revenue by region and also show top 5 customers by spend',
];

export default function PostgresPage() {
  const [connections, setConnections] = useState([]);
  const [selectedConn, setSelectedConn] = useState('');
  const [question, setQuestion] = useState('');
  const [results, setResults] = useState([]); // array for multi-question support
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    authAPI.connections()
      .then(r => {
        const pg = (r.data || []).filter(c => c.db_type === 'postgresql');
        setConnections(pg);
        if (pg.length) setSelectedConn(String(pg[0].id));
      }).catch(() => setConnections([]));
  }, []);

  const conn = connections.find(c => String(c.id) === String(selectedConn));

  const runQuery = async () => {
    if (!question.trim()) return setError('Please enter a question.');
    if (!conn)            return setError('Please select a connection.');
    setLoading(true); setError(''); setResults([]);
    try {
      const uriRes = await authAPI.getUri(conn.id);
      const pg_uri = uriRes.data?.uri || uriRes.data?.connection_string;
      if (!pg_uri) throw new Error('Could not retrieve connection URI.');

      const questions = splitQuestions(question);

      const responses = await Promise.all(
        questions.map(({display, query}) =>
          pgAPI.nlQuery({ pg_uri, question: query, limit: 100 })
            .then(r => ({ ok: true,  question: display, data: r.data }))
            .catch(e => ({ ok: false, question: display, error: e.response?.data?.detail || e.message || 'Query failed' }))
        )
      );
      setResults(responses);
    } catch (err) {
      const detail = err.response?.data?.detail;
      if (Array.isArray(detail)) setError(detail.map(d => d.msg || String(d)).join(', '));
      else setError(typeof detail === 'string' ? detail : (err.message || 'Query failed.'));
    } finally {
      setLoading(false);
    }
  };

  const hasResults = results.length > 0;

  return (
    <div className="query-page fade-in">
      <PageHeader
        title="PostgreSQL Query"
        subtitle="Ask your PostgreSQL database anything in plain English"
        actions={<Badge color="blue"><Database size={12}/> PostgreSQL</Badge>}
      />

      <div className="query-layout">
        <div className="query-input-col">
          <Card>
            <div className="query-form">
              {connections.length === 0 ? (
                <EmptyState icon={<Database size={22}/>} title="No PostgreSQL connections"
                  description="Add a PostgreSQL connection first to start querying." />
              ) : (
                <>
                  <Select label="Connection" value={selectedConn}
                    onChange={e => setSelectedConn(e.target.value)}>
                    {connections.map(c => (
                      <option key={c.id} value={String(c.id)}>
                        {c.name || c.dbname || `Connection ${c.id}`}
                      </option>
                    ))}
                  </Select>

                  <Textarea
                    label="Your Question"
                    value={question}
                    onChange={e => setQuestion(e.target.value)}
                    placeholder="e.g. Total revenue by region and also show top 5 customers by spend"
                    rows={4}
                    onKeyDown={e => { if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) runQuery(); }}
                    hint="Tip: ask multiple questions at once! Press Ctrl+Enter to run"
                  />

                  {error && <Alert type="error" onClose={() => setError('')}>{error}</Alert>}

                  <Button onClick={runQuery} loading={loading} size="lg"
                    icon={loading ? null : <Send size={15}/>} style={{ width: '100%' }}>
                    {loading ? 'Running queries...' : 'Run Query'}
                  </Button>
                </>
              )}
            </div>
          </Card>

          <div className="sample-questions">
            <div className="sample-title"><Sparkles size={13}/> Sample questions</div>
            {SAMPLE_QUESTIONS.map(q => (
              <button key={q} className="sample-btn" onClick={() => setQuestion(q)}>{q}</button>
            ))}
          </div>
        </div>

        <div className="query-result-col">
          {loading && (
            <Card className="query-loading-card">
              <div className="query-loading">
                <div className="query-loading-spinner" />
                <div>
                  <div className="query-loading-title">Running AI pipeline...</div>
                  <div className="query-loading-sub">Schema → Gemini → SQL → Execute → EDA</div>
                </div>
              </div>
            </Card>
          )}

          {!loading && hasResults && (
            <div className="multi-results">
              {results.map((r, i) => (
                <div key={i} className="multi-result-block">
                  {results.length > 1 && (
                    <div className="multi-result-label">
                      <span className="multi-result-num">{i + 1}</span>
                      <span className="multi-result-q">{r.question}</span>
                    </div>
                  )}
                  {r.ok
                    ? <ResultsPanel result={r.data} />
                    : <Alert type="error">{typeof r.error === 'string' ? r.error : JSON.stringify(r.error)}</Alert>
                  }
                </div>
              ))}
            </div>
          )}

          {!loading && !hasResults && (
            <div className="query-empty">
              <div className="query-empty-icon"><Database size={32}/></div>
              <div className="query-empty-title">Ready to query</div>
              <div className="query-empty-sub">Enter a question and hit Run Query to get started</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
